import{_ as t,o as a,c as l,a2 as i}from"./chunks/framework.Bix3-HpO.js";const c=JSON.parse('{"title":"Page Templates","description":"FXT Theme Page Templates","frontmatter":{"title":"Page Templates","description":"FXT Theme Page Templates","weight":70,"extra":{"order":70},"head":[["link",{"rel":"canonical","href":"https://docs.dinomatic.com/docs/fxt/page-templates"}],["meta",{"property":"og:url","content":"https://docs.dinomatic.com/docs/fxt/page-templates"}],["meta",{"property":"og:title","content":"Page Templates"}],["meta",{"property":"og:description","content":"FXT Theme Page Templates"}],["meta",{"name":"twitter:title","content":"Page Templates"}],["meta",{"name":"twitter:description","content":"FXT Theme Page Templates"}]]},"headers":[],"relativePath":"docs/fxt/page-templates.md","filePath":"docs/fxt/page-templates.md"}'),o={name:"docs/fxt/page-templates.md"};function s(r,e,n,p,m,d){return a(),l("div",null,[...e[0]||(e[0]=[i('<h1 id="page-templates" tabindex="-1">Page Templates <a class="header-anchor" href="#page-templates" aria-label="Permalink to &quot;Page Templates&quot;">‚Äã</a></h1><p>FXT theme includes several page templates that you can use to create different types of pages with specific layouts and functionality.</p><hr><h2 id="available-page-templates" tabindex="-1">Available Page Templates <a class="header-anchor" href="#available-page-templates" aria-label="Permalink to &quot;Available Page Templates&quot;">‚Äã</a></h2><h3 id="default-template" tabindex="-1">Default Template <a class="header-anchor" href="#default-template" aria-label="Permalink to &quot;Default Template&quot;">‚Äã</a></h3><p>The standard page template with sidebar and standard layout.</p><p><strong>Features</strong>:</p><ul><li>Standard page layout with sidebar</li><li>Full content area</li><li>Standard navigation</li></ul><h3 id="full-width-template" tabindex="-1">Full Width Template <a class="header-anchor" href="#full-width-template" aria-label="Permalink to &quot;Full Width Template&quot;">‚Äã</a></h3><p>A template that uses the full width of the page without sidebar.</p><p><strong>Features</strong>:</p><ul><li>Full-width layout</li><li>No sidebar</li><li>Maximum content area</li></ul><h3 id="hero-template" tabindex="-1">Hero Template <a class="header-anchor" href="#hero-template" aria-label="Permalink to &quot;Hero Template&quot;">‚Äã</a></h3><p>A template with a prominent hero section at the top.</p><p><strong>Features</strong>:</p><ul><li>Hero section at the top</li><li>Prominent visual impact</li><li>Full-width design</li></ul><h3 id="simple-template" tabindex="-1">Simple Template <a class="header-anchor" href="#simple-template" aria-label="Permalink to &quot;Simple Template&quot;">‚Äã</a></h3><p>A clean, minimal template with simplified layout.</p><p><strong>Features</strong>:</p><ul><li>Clean, minimal design</li><li>Simplified layout</li><li>Focus on content</li></ul><h3 id="top-listing-template" tabindex="-1">Top Listing Template <a class="header-anchor" href="#top-listing-template" aria-label="Permalink to &quot;Top Listing Template&quot;">‚Äã</a></h3><p>A template designed for pages that showcase listings or collections.</p><p><strong>Features</strong>:</p><ul><li>Optimized for listings</li><li>Enhanced visual hierarchy</li><li>Better for multiple items</li></ul><hr><h2 id="how-to-use-page-templates" tabindex="-1">How to Use Page Templates <a class="header-anchor" href="#how-to-use-page-templates" aria-label="Permalink to &quot;How to Use Page Templates&quot;">‚Äã</a></h2><h3 id="selecting-a-template" tabindex="-1">Selecting a Template <a class="header-anchor" href="#selecting-a-template" aria-label="Permalink to &quot;Selecting a Template&quot;">‚Äã</a></h3><ol><li>Create a new page or edit an existing page</li><li>In the page editor, look for the <strong>Page Attributes</strong> section in the right sidebar</li><li>Click on the <strong>Template</strong> dropdown menu</li><li>Select your desired template from the list</li><li>Update or publish your page</li></ol><h3 id="template-specific-features" tabindex="-1">Template-Specific Features <a class="header-anchor" href="#template-specific-features" aria-label="Permalink to &quot;Template-Specific Features&quot;">‚Äã</a></h3><p>Each template may have specific features or requirements:</p><ul><li><strong>Full Width</strong>: Best for content that needs maximum space</li><li><strong>Hero</strong>: Requires featured image for best visual impact</li><li><strong>Simple</strong>: Works well with minimal content</li><li><strong>Top Listing</strong>: Optimized for pages with multiple items or comparisons</li></ul><hr><h2 id="customizing-templates" tabindex="-1">Customizing Templates <a class="header-anchor" href="#customizing-templates" aria-label="Permalink to &quot;Customizing Templates&quot;">‚Äã</a></h2><h3 id="adding-content" tabindex="-1">Adding Content <a class="header-anchor" href="#adding-content" aria-label="Permalink to &quot;Adding Content&quot;">‚Äã</a></h3><p>All templates support standard WordPress blocks and content. You can:</p><ul><li>Add text content</li><li>Insert images and media</li><li>Use FXT theme blocks</li><li>Add custom HTML if needed</li></ul><h3 id="template-limitations" tabindex="-1">Template Limitations <a class="header-anchor" href="#template-limitations" aria-label="Permalink to &quot;Template Limitations&quot;">‚Äã</a></h3><ul><li>Templates are pre-designed layouts</li><li>You cannot modify the template structure itself</li><li>Content and blocks can be added within the template framework</li></ul><hr><h2 id="next-step" tabindex="-1">Next Step <a class="header-anchor" href="#next-step" aria-label="Permalink to &quot;Next Step&quot;">‚Äã</a></h2><p><a href="/docs/fxt/blocks">Blocks</a></p>',41)])])}const u=t(o,[["render",s]]);export{c as __pageData,u as default};
